"use strict";
/**
 * Reclude commands entry point.
 */
const initializeCommands = () => {
    const officeGlobal = globalThis.Office;
    if (!officeGlobal) {
        // eslint-disable-next-line no-console
        console.error('Office runtime unavailable; commands cannot initialize.');
        return;
    }
    if (typeof officeGlobal.onReady === 'function') {
        officeGlobal.onReady(() => undefined);
        return;
    }
    officeGlobal.initialize = () => undefined;
};
initializeCommands();
